namespace InventoryApp.Services;

public record EquipmentItem(
    int Id,
    string Name,
    string Location,
    DateTime LastInspected);

namespace InventoryApp.Services;

public class EquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate a database / API call
        await Task.Delay(800);

        return
        [
            new(1, "Forklift A",      "Warehouse 1", new DateTime(2026, 3, 10)),
            new(2, "Crane B",         "Yard 3",      new DateTime(2026, 1, 22)),
            new(3, "Drill Press C",   "Shop Floor",  new DateTime(2025, 11, 5)),
            new(4, "Lathe D",         "Shop Floor",  new DateTime(2026, 4, 18)),
            new(5, "Conveyor Belt E", "Warehouse 2", new DateTime(2025, 12, 30)),
            new(6, "Welder F",        "Bay 7",       new DateTime(2026, 2, 14)),
            new(7, "Compressor G",    "Utility Room", new DateTime(2026, 5, 1)),
        ];
    }
}

@page "/inventory"
@attribute [StreamRendering]
@rendermode InteractiveServer
@inject EquipmentService Svc

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? items;

    protected override async Task OnInitializedAsync()
    {
        items = await Svc.GetEquipmentAsync();
    }
}

